pipeline.evaluate:
(() => {
  const items = [];
  document.querySelectorAll('.we-lockup').forEach(el => {
    const titleEl = el.querySelector('.we-lockup__title');
    const linkEl = el.querySelector('a');
    if (titleEl && linkEl) {
      items.push({
        title: titleEl.textContent.trim(),
        url: linkEl.href
      });
    }
  });
  return items;
})()
